#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=20000005;
int n,m,s,a[N],ls[N],rs[N],vis[N],root;
ll ans;
stack<int> st;
namespace GenHelper
{
    unsigned z1,z2,z3,z4,b;
    unsigned rand_()
    {
    b=((z1<<6)^z1)>>13;
    z1=((z1&4294967294U)<<18)^b;
    b=((z2<<2)^z2)>>27;
    z2=((z2&4294967288U)<<2)^b;
    b=((z3<<13)^z3)>>21;
    z3=((z3&4294967280U)<<7)^b;
    b=((z4<<3)^z4)>>12;
    z4=((z4&4294967168U)<<13)^b;
    return (z1^z2^z3^z4);
    }
}
void srand(unsigned x)
{using namespace GenHelper;
z1=x; z2=(~x)^0x233333333U; z3=x^0x1234598766U; z4=(~x)+51;}
int read()
{
    using namespace GenHelper;
    int a=rand_()&32767;
    int b=rand_()&32767;
    return a*32768+b;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m>>s;
	srand(s);
	for(int i=1;i<=n;i++)
	{
		a[i]=read();
		bool flag=0;
		int lst;
		while(!st.empty()&&a[st.top()]<a[i])
		{
			lst=st.top();
			st.pop();
			flag=1;
		}
		if(!st.empty()) rs[st.top()]=i;
		if(flag) ls[i]=lst;
		st.push(i);
	}
	for(int i=1;i<=n;i++)
	{
		vis[ls[i]]=vis[rs[i]]=1;
	}
	for(int i=1;i<=n;i++)
	{
		if(vis[i]==0)
		{
			root=i;
			break;
		}
	}
	while(m--)
	{
		int l=read()%n+1,r=read()%n+1;
		if(l>r)
		{
			swap(l,r);
		}
		int num=root;
		while(num<l||num>r)
		{
			if(num<l) num=rs[num];
			else num=ls[num];
		}
		ans+=a[num];
	}
	cout<<ans;
	return 0;
}
